((c,r)=>{c.behaviors.sahoRelatedTabs={attach:o=>{r("saho-reltabs","[data-saho-reltabs]",o).forEach(e=>{const s=[...e.querySelectorAll(".saho-reltabs__tab")],i=[...e.querySelectorAll(".saho-reltabs__panel")];s.forEach(t=>{t.addEventListener("click",()=>{const h=t.getAttribute("data-tab");s.forEach(a=>{const l=a===t;a.classList.toggle("is-active",l),a.setAttribute("aria-selected",l?"true":"false")}),i.forEach(a=>{a.classList.toggle("is-active",a.getAttribute("data-panel")===h)})})})})}}})(Drupal,once);
